INSERT INTO `articletranslation` VALUES (57,29,'en','Artikel A-A-1','<p><strong>Artikel A-A-1</strong></p><img src=\"/uploads/1781264334660-mt6jg5.png\"><p></p><p>Ok</p>'),(58,29,'id','Artikel A-A-1','<p><strong>Artikel A-A-1</strong></p><img src=\"/uploads/1781264357471-xlmr3n.png\"><p></p><p>OK</p>'),(59,30,'en','Welcome to Knowledge Management Center','Welcome! This platform helps you find information.'),(60,30,'id','Selamat Datang di Pusat Manajemen Pengetahuan','Selamat datang! Platform ini membantu Anda menemukan informasi.'),(73,39,'en','Test Artikel','<table><tr><td></td><td></td><td></td><td></td></tr><tr><td><p>No</p></td><td><p>: 070/DD/IT/IM/V/2027</p></td><td><p><img alt=\"Checkmark with solid fill\" src=\"data:image/png;base64,\" /></p></td><td><p>Untuk ditindaklanjuti</p></td></tr><tr><td><p>Kepada </p></td><td><p>: Departemen Keuangan</p></td><td></td><td><p>Untuk diperhatikan</p></td></tr><tr><td><p>Dari</p></td><td><p>: Departemen IT Development</p></td><td></td><td><p>Untuk dipelajari</p></td></tr><tr><td><p>Perihal</p></td><td><p>: Maintenance Sandra 2 Mei 2026</p></td><td></td><td><p>Pemberitahuan</p></td></tr><tr><td><p>Tanggal</p></td><td><p>: 26 Mei 2026</p></td><td></td><td></td></tr></table><p><strong>INTERNAL MEMO</strong></p><p><strong>Assalamu’alaikum Warrahmatullahi Wabarakatuh  </strong></p><p>Teriring do’a dan salam semoga Allah SWT tetap melimpahkan rahmat dan hidayah-Nya kepada kita sekalian dan semoga kita tetap menjadi orang-orang yang beruntung. Shalawat dan salam tetap tercurahkan kepada Nabi Muhammad SAW, keluarga, dan sahabatnya. </p><p>Dalam rangka ajuan pembayaran Maintenance Sandra 2, maka kami bermaksud untuk mengajukan pembayaran bulan Mei 2026.</p><p>Dengan ini kami memohon izin untuk ditindaklanjuti ajuan pembayaran dengan nilai Rp. 11.000.000,- (Sebelas Juta Rupiah) untuk pembayaran Maintenance Sandra 2. Untuk informasi lebih lanjut dapat menghubungi <strong>08996088213  Sdr. Hendra Gunawan.</strong></p><p>Demikian surat ini kami sampaikan. Atas perhatian dan kesediaan Bapak/Ibu, kami haturkan terima kasih.</p><p><strong>Wassalamu’alaikum Warrahmatullahi Wabarakatuh  </strong></p><p>Hormat kami,</p><p><img src=\"data:image/jpeg;base64,\" /> </p><p><strong>Jenar S useno<br />Plt SO IT Development</strong></p>'),(74,39,'id','Test Artikel dari Dokumen','<table><tr><td></td><td></td><td></td><td></td></tr><tr><td><p>No</p></td><td><p>: 070/DD/IT/IM/V/2027</p></td><td><p><img alt=\"Checkmark with solid fill\" src=\"data:image/png;base64,\" /></p></td><td><p>Untuk ditindaklanjuti</p></td></tr><tr><td><p>Kepada </p></td><td><p>: Departemen Keuangan</p></td><td></td><td><p>Untuk diperhatikan</p></td></tr><tr><td><p>Dari</p></td><td><p>: Departemen IT Development</p></td><td></td><td><p>Untuk dipelajari</p></td></tr><tr><td><p>Perihal</p></td><td><p>: Maintenance Sandra 2 Mei 2026</p></td><td></td><td><p>Pemberitahuan</p></td></tr><tr><td><p>Tanggal</p></td><td><p>: 26 Mei 2026</p></td><td></td><td></td></tr></table><p><strong>INTERNAL MEMO</strong></p><p><strong>Assalamu’alaikum Warrahmatullahi Wabarakatuh  </strong></p><p>Teriring do’a dan salam semoga Allah SWT tetap melimpahkan rahmat dan hidayah-Nya kepada kita sekalian dan semoga kita tetap menjadi orang-orang yang beruntung. Shalawat dan salam tetap tercurahkan kepada Nabi Muhammad SAW, keluarga, dan sahabatnya. </p><p>Dalam rangka ajuan pembayaran Maintenance Sandra 2, maka kami bermaksud untuk mengajukan pembayaran bulan Mei 2026.</p><p>Dengan ini kami memohon izin untuk ditindaklanjuti ajuan pembayaran dengan nilai Rp. 11.000.000,- (Sebelas Juta Rupiah) untuk pembayaran Maintenance Sandra 2. Untuk informasi lebih lanjut dapat menghubungi <strong>08996088213  Sdr. Hendra Gunawan.</strong></p><p>Demikian surat ini kami sampaikan. Atas perhatian dan kesediaan Bapak/Ibu, kami haturkan terima kasih.</p><p><strong>Wassalamu’alaikum Warrahmatullahi Wabarakatuh  </strong></p><p>Hormat kami,</p><p><img src=\"data:image/jpeg;base64,\" /> </p><p><strong>Jenar S useno<br />Plt SO IT Development</strong></p>');
